class Solution {
    public double new21Game(int n, int k, int maxPts) {
        if (k > n || maxPts == 1) return 1.0;
        double[] dp = new double[n + 1];
        dp[0] = 1.0;
        double sum = 1.0;
        for (int i = 1; i <= k - 1; i++) {
            dp[i] = 1.0 / maxPts;
            sum += dp[i];
        }
        for (int i = k; i <= n; i++) {
            dp[i] = (sum / maxPts);
            if (i < n) sum -= dp[i - maxPts + 1];
        }
        return dp[n];
    }
}
